import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XssSecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String sanitizedInput = sanitizeUserInput(userInput);

        // Output the sanitized user input
        PrintWriter out = response.getWriter();
        out.println("<html><body>");
        out.println("User input: " + sanitizedInput);
        out.println("</body></html>");
    }

    private String sanitizeUserInput(String userInput) {
        // Implement proper sanitization logic here based on your requirements
        // For example, you can use OWASP ESAPI library or a custom sanitizer function

        // Here is a basic example of HTML encoding to prevent XSS
        return userInput != null ? userInput.replace("<", "&lt;").replace(">", "&gt;") : "";
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
